import React from 'react';

function App() {
  return (
    <div style={{ 
      background: '#0a0a0a', 
      color: 'white', 
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'Arial, sans-serif'
    }}>
      <div style={{ textAlign: 'center' }}>
        <h1 style={{ color: '#ff4d2d', fontSize: '3rem' }}>ZE Auto Service</h1>
        <p style={{ color: '#999', fontSize: '1.2rem' }}>Workshop in Parit Raja, Batu Pahat</p>
      </div>
    </div>
  );
}

export default App;
